parameters.jsCode:
const ausencia = $('Preparar Datos').first().json;
const guardias = $input.all().map(i => i.json);

// Buscar profesor de guardia para este dia y franja
const sustituto = guardias.find(g =>
  (g.dia_semana || '').toLowerCase() === ausencia.dia_semana.toLowerCase() &&
  (g.franja_horaria || '') === ausencia.franja_horaria
);

if (sustituto) {
  return [{ json: {
    ...ausencia,
    sustituto_nombre: sustituto.profesor_guardia,
    sustituto_email: sustituto.email_profesor,
    asignado: true
  }}];
} else {
  return [{ json: {
    ...ausencia,
    sustituto_nombre: 'No disponible',
    sustituto_email: '',
    asignado: false
  }}];
}

